// And groups predicates with the AND operator between them.
func And(predicates ...predicate.AgentProvider) predicate.AgentProvider {
	return predicate.AgentProvider(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.AgentProvider) predicate.AgentProvider {
	return predicate.AgentProvider(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.AgentProvider) predicate.AgentProvider {
	return predicate.AgentProvider(sql.NotPredicates(p))
}
